import { initializeApp } from "firebase/app";
import { getFirestore, doc, setDoc, getDoc, onSnapshot, enableIndexedDbPersistence } from "firebase/firestore";
import { Workspace } from "../types";

// --- CONFIGURATION REQUIRED ---
// 1. Create a project at https://console.firebase.google.com/
// 2. Add a Web App to get these values
// 3. Create a Firestore Database (Start in Test Mode)
// -----------------------------------------------------------
const firebaseConfig = {
  apiKey: "AIzaSyDGw9Lj6vfpRP_NtNLbMy5rezrJwfzTf64",
  authDomain: "brand-marketing-app-2f26e.firebaseapp.com",
  projectId: "brand-marketing-app-2f26e",
  storageBucket: "brand-marketing-app-2f26e.firebasestorage.app",
  messagingSenderId: "819664755601",
  appId: "1:819664755601:web:d4f919aa1942c6760c5830"
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// Enable Offline Persistence
// This allows the app to work offline and syncs changes when connectivity returns.
enableIndexedDbPersistence(db).catch((err) => {
  if (err.code == 'failed-precondition') {
    // Multiple tabs open, persistence can only be enabled in one tab at a a time.
    console.warn('Firebase Persistence: Multiple tabs open, persistence disabled');
  } else if (err.code == 'unimplemented') {
    // The current browser does not support all of the features required to enable persistence
    console.warn('Firebase Persistence: Browser not supported');
  }
});

// We will store all workspaces in a single document for simplicity in this MVP.
// In a production app, you might split this into collections per user.
const DB_COLLECTION = "app_data";
const DB_DOC_ID = "main_workspace";

export const saveWorkspacesToFirestore = async (workspaces: Workspace[]) => {
  try {
    const docRef = doc(db, DB_COLLECTION, DB_DOC_ID);
    // We overwrite the document with the new state
    await setDoc(docRef, { workspaces, lastUpdated: new Date().toISOString() }, { merge: true });
    // console.log("Saved to Firebase");
  } catch (e) {
    console.error("Error adding document: ", e);
  }
};

export const loadWorkspacesFromFirestore = async (): Promise<Workspace[] | null> => {
  try {
    const docRef = doc(db, DB_COLLECTION, DB_DOC_ID);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      return docSnap.data().workspaces as Workspace[];
    } else {
      return null;
    }
  } catch (e) {
    console.error("Error loading document: ", e);
    return null;
  }
};

// Optional: Real-time listener
export const subscribeToWorkspaces = (callback: (ws: Workspace[]) => void) => {
  const docRef = doc(db, DB_COLLECTION, DB_DOC_ID);
  return onSnapshot(docRef, (doc) => {
    if (doc.exists()) {
      callback(doc.data().workspaces as Workspace[]);
    }
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
