  Plus, 
  FileImage, 
  Sparkles, 
  BarChart2, 
  Users,
  Search,
  X,
  ChevronDown,
  Check,
  Globe,
  MessageSquare,
  HardDrive,
  LayoutGrid,
  Trash2,
  Cloud,
  Loader2
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'My Board',
    color: '#007AFF',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

