                  <div className="w-8 h-8 rounded-full bg-gray-300 border-2 border-white flex items-center justify-center text-xs font-semibold text-gray-600">SS</div>
                  <button className="w-8 h-8 rounded-full bg-[#F2F2F7] border-2 border-white flex items-center justify-center text-gray-400 hover:bg-gray-200">
                    <UserPlus size={14} />
                  </button>
                </div>

                {/* Right: Tools (Drive + Comments) */}
                <div className="flex items-center gap-2">
                  {/* Drive Integration */}
                  <DriveSyncButton 
                      sku={sku}
                      title={title}
                      hasAssets={finalAssets.length > 0}
                      isSynced={driveInfo.synced}
                      driveUrl={driveInfo.url}
                      onSync={handleDriveSync}
                  />

                  {viewMode === 'edit' ? (
                    <button 
                      onClick={(e) => { e.stopPropagation(); setViewMode('comments'); }}
                      className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center relative"
                    >
                      <MessageSquare size={18} />
                      {comments.length > 0 && (
                        <span className="absolute top-1.5 right-2 w-2 h-2 bg-red-500 rounded-full"></span>
                      )}
                    </button>
                  ) : (
                    <button 
                      onClick={(e) => { e.stopPropagation(); setViewMode('edit'); }}
                      className="w-9 h-9 rounded-full bg-[#F2F2F7] text-gray-600 hover:bg-gray-200 hover:text-gray-900 transition-all flex items-center justify-center"
                    >
                      <Pencil size={18} />
                    </button>
                  )}
                </div>
              </div>
            </>
          )}
        </div>
      </BaseCard>

      {/* Media Lightbox */}
      {previewContext && (
        <MediaPreviewOverlay 
          initialItem={previewContext.item}
          items={previewContext.list}
          onClose={() => setPreviewContext(null)} 
        />
      )}
    </>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType, Workspace } from './types';
import { Canvas } from './components/Canvas';
import { saveWorkspacesToFirestore, loadWorkspacesFromFirestore } from './services/firebase';
import { 
  Plus, 
  FileImage, 
  Search,
  ChevronDown,
  Check,
  LayoutGrid,
  Trash2,
  Cloud,
  Loader2
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'My Board',
    color: '#007AFF',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  // Store position for the floating menu: { id, x, y }
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Ref to track if the initial load has happened so we don't overwrite DB with empty init state
  const isLoadedRef = useRef(false);

  // --- FIREBASE INTEGRATION ---

  // 1. Load data on mount
  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      const savedData = await loadWorkspacesFromFirestore();
      if (savedData && savedData.length > 0) {
        setWorkspaces(savedData);
        // Ensure active workspace ID exists in loaded data, otherwise default to first
        const hasActive = savedData.find(w => w.id === activeWorkspaceId);
        if (!hasActive) {
          setActiveWorkspaceId(savedData[0].id);
        }
      }
      isLoadedRef.current = true;
      setIsLoading(false);
    };
    init();
  }, []);

  // 2. Auto-save when workspaces change (Debounced)
  useEffect(() => {
    if (!isLoadedRef.current) return;

    setIsSaving(true);
    // Reduced debounce to 1s for snappier saves
    const handler = setTimeout(() => {
      saveWorkspacesToFirestore(workspaces).then(() => {
        setIsSaving(false);
      });
    }, 1000); 

    return () => clearTimeout(handler);
  }, [workspaces]);

  // 3. Safety: Warn user if they try to close while saving
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (isSaving) {
        e.preventDefault();
        e.returnValue = '';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [isSaving]);

  // ---------------------------

  // Close color picker when clicking outside
  useEffect(() => {
    const handleClickOutside = () => setColorPickerState(null);
    window.addEventListener('click', handleClickOutside);
    window.addEventListener('scroll', handleClickOutside, true); // Close on scroll
    return () => {
      window.removeEventListener('click', handleClickOutside);
      window.removeEventListener('scroll', handleClickOutside, true);
    };
  }, []);

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
  };

  const updateWorkspaceName = (id: string, name: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, name } : w));
  };

  const deleteWorkspace = (id: string) => {
    if (workspaces.length <= 1) {
        alert("Cannot delete the last workspace.");
        return;
    }
    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) {
        setActiveWorkspaceId(newWorkspaces[0].id);
    }
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({
        id,
        x: rect.left + rect.width / 2,
        y: rect.top
      });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : (type === CardType.GRID_PLANNER ? 320 : 360),
      height: type === CardType.GRID_PLANNER ? 500 : 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  // --- Menu Data Configuration ---

  const frequentTools = [
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'grid', 
      label: 'Feed Planner', 
      desc: 'Visual monthly calendar', 
      icon: <LayoutGrid size={24} />, 
      iconColor: 'text-blue-600',
      bg: 'bg-blue-50',
      action: () => addCard(CardType.GRID_PLANNER)
    },
  ];

  const integrationTools = [
    { 
      id: 'pinterest', 
      label: 'Pinterest', 
      desc: 'Inspiration moodboard', 
      icon: (
        <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
           <path d="M12.017 0C5.396 0 .029 5.367.029 11.987c0 5.079 3.158 9.417 7.618 11.162-.105-.949-.199-2.403.041-3.439.219-.937 1.406-5.957 1.406-5.957s-.359-.72-.359-1.781c0-1.663.967-2.911 2.168-2.911 1.024 0 1.518.769 1.518 1.688 0 1.029-.653 2.567-.992 3.992-.285 1.193.6 2.165 1.775 2.165 2.128 0 3.768-2.245 3.768-5.487 0-2.861-2.063-4.869-5.008-4.869-3.41 0-5.409 2.562-5.409 5.199 0 1.033.394 2.143.889 2.741.099.12.112.225.085.345-.09.375-.293 1.199-.334 1.363-.053.225-.172.271-.399.165-1.487-.695-2.419-2.875-2.419-4.629 0-3.773 2.749-7.253 7.951-7.253 4.173 0 7.41 2.967 7.41 6.923 0 4.133-2.607 7.462-6.233 7.462-1.214 0-2.354-.629-2.758-1.379l-.749 2.848c-.269 1.045-1.004 2.352-1.498 3.146 1.123.345 2.306.535 3.55.535 6.607 0 11.985-5.365 11.985-11.987C23.97 5.367 18.62 0 12.017 0z"/>
        </svg>
      ),
      color: 'bg-red-100 text-[#E60023]',
      tag: 'NEW',
      action: () => addCard(CardType.PINTEREST)
    }
  ];

  const filterItem = (item: any) => 
    item.label.toLowerCase().includes(searchTerm.toLowerCase()) || 
    item.desc.toLowerCase().includes(searchTerm.toLowerCase());

  if (isLoading) {
    return (
      <div className="w-full h-screen flex flex-col items-center justify-center bg-[#F2F2F7] text-gray-400">
        <Loader2 size={32} className="animate-spin mb-4 text-[#007AFF]" />
        <p className="text-[13px] font-medium">Loading Workspace...</p>
      </div>
    );
  }

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">

      {/* Saving Indicator */}
      <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 backdrop-blur border border-black/5 shadow-sm transition-opacity duration-300 ${isSaving ? 'opacity-100' : 'opacity-0'}`}>
        <Cloud size={14} className="text-[#007AFF]" />
        <span className="text-[11px] font-semibold text-gray-500">Saving...</span>
      </div>

      {/* Main Canvas Area */}
      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
        />
      </div>

      {/* Trigger Zone (Top Left) with Auto-Open on Hover */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button 
          onClick={() => setIsDrawerOpen(true)}
          className="relative w-14 h-14 rounded-full group transition-all duration-500 hover:scale-110 active:scale-95 shadow-2xl"
        >
           {/* Shimmering Perimeter - Rotating Light Beam */}
           <div className="absolute -inset-[2px] rounded-full overflow-hidden z-0">
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300%] h-[300%] bg-[conic-gradient(from_0deg,transparent_0_340deg,rgba(255,255,255,1)_360deg)] animate-[spin_4s_linear_infinite] opacity-60" />
           </div>

           {/* Liquid Glass Body */}
           <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-md border border-white/60 flex items-center justify-center z-10 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9)]">
              <Plus size={26} strokeWidth={1} className="text-gray-600 group-hover:text-gray-900 transition-colors duration-300" />
           </div>
        </button>
      </div>

      {/* Side Drawer Overlay (Left Side) - Auto close on mouse leave */}
      <div 
        className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`}
        onMouseLeave={() => setIsDrawerOpen(false)}
      >

        {/* Drawer Content */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">

          {/* Header & Search */}
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus={isDrawerOpen}
                type="text" 
                placeholder="Search all nodes" 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none placeholder-gray-400"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          {/* Scrollable List */}
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            <div className="p-5 space-y-8">

              {/* Frequently Used Section */}
              {(!searchTerm || frequentTools.some(filterItem)) && (
                <div className="space-y-3">
                  <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Frequently Used</h3>
                  <div className="grid grid-cols-2 gap-3">
                    {frequentTools.filter(filterItem).map(tool => (
                      <button 
                        key={tool.id}
                        onClick={tool.action}
                        className="flex flex-col items-start p-4 rounded-2xl bg-white border border-gray-200 hover:border-gray-300 hover:shadow-md transition-all active:scale-[0.98] text-left group"
                      >
                        <div className={`w-10 h-10 rounded-xl ${tool.bg} ${tool.iconColor} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>
                          {tool.icon}
                        </div>
                        <div className="font-semibold text-gray-900 text-[14px] leading-tight mb-1">{tool.label}</div>
                        <div className="text-[12px] text-gray-500 leading-snug line-clamp-2">{tool.desc}</div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Integrations / All Tools Section */}
              {(!searchTerm || integrationTools.some(filterItem)) && (
                <div className="space-y-3">
                   <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Integrations</h3>
                   <div className="space-y-1">
                      {integrationTools.filter(filterItem).map(tool => (
                        <button
                          key={tool.id}
                          onClick={tool.action}
                          className="w-full flex items-center gap-4 p-3 rounded-xl hover:bg-gray-50 transition-colors group text-left"
                        >
                          <div className={`w-10 h-10 rounded-xl ${tool.color} flex items-center justify-center shadow-sm border border-black/5 flex-shrink-0 group-hover:scale-105 transition-transform`}>
                            {tool.icon}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-0.5">
                               <span className="font-semibold text-gray-900 text-[14px]">{tool.label}</span>
                               {tool.tag && (
                                 <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-md ${tool.tag === 'MCP' ? 'bg-blue-100 text-blue-600' : (tool.tag === 'NEW' ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600')}`}>
                                   {tool.tag}
                                 </span>
                               )}
                            </div>
                            <p className="text-[13px] text-gray-500 truncate">{tool.desc}</p>
                          </div>
                          <div className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity">
                            <Plus size={16} />
                          </div>
                        </button>
                      ))}
                   </div>
                </div>
              )}

              {searchTerm && !frequentTools.some(filterItem) && !integrationTools.some(filterItem) && (
                <div className="text-center py-10 text-gray-400">
                  <p>No tools found</p>
                </div>
              )}

            </div>
          </div>
        </div>
      </div>


      {/* Bottom Spreadsheet Navigation (Floating Overlay) */}
      <div className="absolute bottom-6 left-6 right-0 z-40 flex items-end justify-start pointer-events-none">
        <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2 pl-2 pr-4 pointer-events-auto max-w-full">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group flex-shrink-0">
                <button
                  onClick={() => setActiveWorkspaceId(ws.id)}
                  className={`
                    relative h-11 px-4 min-w-[100px] max-w-[180px] flex items-center gap-2.5 rounded-full transition-all duration-300 select-none
                    bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 
                    shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)]
                    ${isActive 
                      ? 'text-gray-900 font-bold scale-100 z-10 ring-1 ring-white/50' 
                      : 'text-gray-500 hover:text-gray-900 hover:scale-[1.02] active:scale-[0.98] z-0 opacity-70 hover:opacity-100'
                    }
                  `}
                >
                  <div 
                    className={`w-2 h-2 rounded-full shadow-sm transition-transform duration-300 border border-white/50 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`}
                    style={{ backgroundColor: ws.color || '#8E8E93' }}
                  />
                  <span className="truncate text-[13px] tracking-tight">{ws.name}</span>

                  {isActive && (
                    <div 
                      onClick={(e) => toggleColorPicker(e, ws.id)}
                      className="ml-auto p-1 -mr-1 rounded-full hover:bg-black/5 text-gray-400 cursor-pointer transition-colors"
                    >
                      <ChevronDown size={12} strokeWidth={2.5} />
                    </div>
                  )}
                </button>
              </div>
            );
          })}

          <button 
            onClick={addWorkspace}
            className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"
          >
            <Plus size={20} strokeWidth={2.5} />
          </button>
        </div>
      </div>

      {/* Fixed Settings Menu (Color, Rename, Delete) */}
      {colorPickerState && (
        <div 
          onClick={(e) => e.stopPropagation()}
          className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] flex flex-col gap-3 w-56 animate-in fade-in zoom-in-95 duration-200 z-[100]"
          style={{
            left: colorPickerState.x,
            top: colorPickerState.y - 12,
            transform: 'translate(-50%, -100%)' // Center horizontally, place above
          }}
        >
          {/* Rename Field */}
          <input 
            type="text"
            className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#007AFF]/20 transition-all"
            placeholder="Workspace Name"
            value={workspaces.find(w => w.id === colorPickerState.id)?.name || ''}
            onChange={(e) => updateWorkspaceName(colorPickerState.id, e.target.value)}
            autoFocus
          />

          {/* Color Grid */}
          <div>
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block px-1">Tab Color</span>
              <div className="grid grid-cols-7 gap-1.5">
                {TAB_COLORS.map(c => (
                    <button
                    key={c}
                    onClick={() => updateWorkspaceColor(colorPickerState.id, c)}
                    className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5"
                    style={{ backgroundColor: c }}
                    >
                    {workspaces.find(w => w.id === colorPickerState.id)?.color === c && (
                        <Check size={12} className="text-white drop-shadow-md" />
                    )}
                    </button>
                ))}
              </div>
          </div>

          <div className="h-px bg-black/5 w-full my-0.5"></div>

          {/* Delete Button */}
          <button 
             onClick={() => deleteWorkspace(colorPickerState.id)}
             className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"
          >
             <Trash2 size={14} />
             <span>Delete Workspace</span>
          </button>

          {/* Pointer Arrow */}
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/80 backdrop-blur-xl border-r border-b border-white/40 rotate-45 transform"></div>
        </div>
      )}
    </div>
  );
}

