  // Initialize defaults
  useEffect(() => {
    if (!content.fontFamily) {
        onUpdateContent(card.id, {
            ...content,
            fontSize: content.fontSize || 24,
            fontFamily: 'Inter',
            textAlign: 'left',
            color: '#1C1C1E'
        });
