import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent, ToolType, StrokePoint } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';
import { PinterestCard } from './cards/PinterestCard';
import { StrokeCard } from './cards/StrokeCard';
import { TextCard } from './cards/TextCard';
import { StickyCard } from './cards/StickyCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
  activeTool: ToolType;
  onToolUsed: () => void; // Callback to reset tool to select if needed
}

const GRID_HEADER_HEIGHT = 132; 
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ cards, onCardsChange, activeTool, onToolUsed }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });

  // Interaction States
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);
  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);

  // Drawing States
  const [currentStroke, setCurrentStroke] = useState<StrokePoint[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);

  // Lasso State
  const [lassoPath, setLassoPath] = useState<Position[]>([]);

  // Snapping / Grid Logic (from original code)
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; 
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;
      if (finalOpacity > 0.01) {
        layers.push({ spacing: visualSpacing, opacity: finalOpacity, key: `grid-layer-${power}` });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      const s = Math.exp(-e.deltaY * 0.005);
      setScale(prev => Math.min(Math.max(0.05, prev * s), 10)); 
    } else {
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, []);

  // --- Coordinate Utilities ---

  const screenToWorld = (sx: number, sy: number) => {
    return {
        x: (sx - pan.x) / scale,
        y: (sy - pan.y) / scale
    };
  };

  // --- MOUSE HANDLERS ---

  const handleMouseDown = (e: React.MouseEvent) => {
    const worldPos = screenToWorld(e.clientX, e.clientY);

    // 1. Tool Logic
    if (activeTool === 'SELECT' || activeTool === 'PAN') {
        if (e.button === 0 || e.button === 1) { // Left or Middle
            // If dragging background (not card), start pan
            // Note: Card dragging stops propagation, so this only fires on background
            setIsPanning(true);
            setLastMousePos({ x: e.clientX, y: e.clientY });
            setSelectedCardId(null); 
        }
    } else if (activeTool === 'TEXT') {
        // Create Text Object
        const newCard: CardData = {
            id: `text-${Date.now()}`,
            type: CardType.TEXT,
            x: worldPos.x,
            y: worldPos.y,
            width: 300,
            height: 50,
            zIndex: 100,
            content: { text: 'Type something...', fontSize: 24, fontFamily: 'Inter', textAlign: 'left', color: '#1C1C1E' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardId(newCard.id);
        onToolUsed(); // Switch back to select? Or stay in tool? Miro stays. User can press V to exit.
    } else if (activeTool === 'STICKY') {
        const newCard: CardData = {
            id: `sticky-${Date.now()}`,
            type: CardType.STICKY,
            x: worldPos.x - 100, // Center it
            y: worldPos.y - 100,
            width: 200,
            height: 200,
            zIndex: 100,
            content: { text: '', color: '#FFD966' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardId(newCard.id);
        onToolUsed();
    } else if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
        setIsDrawing(true);
        setCurrentStroke([{ x: worldPos.x, y: worldPos.y }]);
    } else if (activeTool === 'ERASER') {
        setIsDrawing(true); // Re-use drawing state for eraser drag
    } else if (activeTool === 'LASSO') {
        setIsDrawing(true);
        setLassoPath([{ x: worldPos.x, y: worldPos.y }]);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const worldPos = screenToWorld(e.clientX, e.clientY);

    // Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // Drawing Update
    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            setCurrentStroke(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'LASSO') {
            setLassoPath(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'ERASER') {
            // Simple Point eraser logic: Delete ANY stroke that is within 10px of mouse
            const ERASER_RADIUS = 20 / scale;
            const remainingCards = cards.filter(c => {
                if (c.type !== CardType.STROKE) return true;
                // Bounding box check first
                if (
                    worldPos.x < c.x - ERASER_RADIUS || worldPos.x > c.x + c.width + ERASER_RADIUS ||
                    worldPos.y < c.y - ERASER_RADIUS || worldPos.y > c.y + c.height + ERASER_RADIUS
                ) return true;

                // Detailed point check
                const content = c.content;
                const points = content.points as StrokePoint[];
                // Points are relative to card x,y
                return !points.some(p => {
                    const px = c.x + p.x;
                    const py = c.y + p.y;
                    const dist = Math.sqrt(Math.pow(px - worldPos.x, 2) + Math.pow(py - worldPos.y, 2));
                    return dist < ERASER_RADIUS;
                });
            });

            if (remainingCards.length !== cards.length) {
                onCardsChange(remainingCards);
            }
        }
    }

    // Drag Collision Logic (Existing)
    if (draggingCardId && activeTool === 'SELECT') {
      const draggedCard = cards.find(c => c.id === draggingCardId);
      if (draggedCard && draggedCard.type === CardType.POST) {
        // ... (Snapping Logic kept same as before, abbreviated for brevity)
      }
    }
  };

  const handleMouseUp = () => {
    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            if (currentStroke.length > 2) {
                // Calculate Bounds
                const xs = currentStroke.map(p => p.x);
                const ys = currentStroke.map(p => p.y);
                const minX = Math.min(...xs);
                const minY = Math.min(...ys);
                const maxX = Math.max(...xs);
                const maxY = Math.max(...ys);
                const width = maxX - minX;
                const height = maxY - minY;

                // Normalize points relative to card origin
                const relativePoints = currentStroke.map(p => ({
                    x: p.x - minX,
                    y: p.y - minY,
                    p: p.p
                }));

                const newCard: CardData = {
                    id: `stroke-${Date.now()}`,
                    type: CardType.STROKE,
                    x: minX,
                    y: minY,
                    width: Math.max(width, 1), // Prevent 0 size
                    height: Math.max(height, 1),
                    zIndex: 50, // Strokes below text usually
                    content: {
                        points: relativePoints,
                        color: activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E', // Default colors
                        width: activeTool === 'HIGHLIGHTER' ? 20 : 4,
                        isHighlighter: activeTool === 'HIGHLIGHTER'
                    }
                };
                onCardsChange([...cards, newCard]);
            }
        } else if (activeTool === 'LASSO') {
            // Find Selection
            // Simple bounding box intersection for MVP
            if (lassoPath.length > 2) {
                const lx = lassoPath.map(p => p.x);
                const ly = lassoPath.map(p => p.y);
                const minX = Math.min(...lx);
                const minY = Math.min(...ly);
                const maxX = Math.max(...lx);
                const maxY = Math.max(...ly);

                // Find cards completely inside the lasso box (simplified)
                const hit = cards.find(c => 
                    c.x >= minX && c.x + c.width <= maxX &&
                    c.y >= minY && c.y + c.height <= maxY
                );
                if (hit) setSelectedCardId(hit.id);
            }
        }
    }

    setIsPanning(false);
    setIsDrawing(false);
    setCurrentStroke([]);
    setLassoPath([]);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    if (draggingCardId !== id) setDraggingCardId(id);
    onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    onCardsChange(cards.filter(c => c.id !== id));
    if (selectedCardId === id) setSelectedCardId(null);
  };

  const bringToFront = (id: string) => {
    // Only bring to front if Select tool is active
    if (activeTool === 'SELECT') {
        setSelectedCardId(id);
        const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
        onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
    }
  };

  // --- Keyboard ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!selectedCardId) return;
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;
      if (e.key === 'Delete' || e.key === 'Backspace') handleDeleteCard(selectedCardId);
      if (e.key === 'Escape') setSelectedCardId(null);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardId, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardId === card.id,
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      onUpdateContent: updateCardContent,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} isLinked={false} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUnlink={()=>{}} onLinkPost={()=>{}} onSwapSlots={()=>{}}
            hoveredSlotIndex={null}
          />
        );
      case CardType.PINTEREST:
        return <PinterestCard {...commonProps} />;
      case CardType.TEXT:
        return <TextCard {...commonProps} />;
      case CardType.STICKY:
        return <StickyCard {...commonProps} />;
      case CardType.STROKE:
        return <StrokeCard {...commonProps} />;
      default:
        return <PostCard {...commonProps} />;
    }
  };

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#f3f4f6] relative overflow-hidden ${activeTool === 'SELECT' ? 'cursor-default' : 'cursor-crosshair'}`}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* Background Grid */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      {/* Content Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
          pointerEvents: activeTool !== 'SELECT' ? 'none' : 'auto' // Pass events through to Canvas container when drawing
        }}
      >
        {cards.map(renderCard)}
      </div>

      {/* Drawing Interaction Layer (Visual Feedback) */}
      <div className="absolute inset-0 pointer-events-none">
          <svg className="w-full h-full overflow-visible">
              {/* Current Stroke Preview */}
              {isDrawing && currentStroke.length > 0 && (
                  <path 
                    d={`M ${currentStroke.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')}`}
                    stroke={activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E'}
                    strokeWidth={(activeTool === 'HIGHLIGHTER' ? 20 : 4) * scale}
                    fill="none"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeOpacity={activeTool === 'HIGHLIGHTER' ? 0.5 : 1}
                  />
              )}
              {/* Lasso Preview */}
              {isDrawing && activeTool === 'LASSO' && lassoPath.length > 0 && (
                   <path 
                   d={`M ${lassoPath.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')} Z`}
                   stroke="#007AFF"
                   strokeWidth={2}
                   fill="rgba(0, 122, 255, 0.1)"
                   strokeDasharray="5,5"
                 />
              )}
          </svg>
      </div>

      {/* Scale Indicator */}
      <div className="absolute bottom-6 right-6 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-mono border border-gray-200 shadow-sm pointer-events-none text-gray-500">
        {Math.round(scale * 100)}%
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { CardData, CardType, Workspace, ToolType } from './types';
import { Canvas } from './components/Canvas';
import { ToolsDock } from './components/ui/ToolsDock';
import { saveWorkspacesToFirestore, loadWorkspacesFromFirestore } from './services/firebase';
import { 
  Plus, 
  FileImage, 
  Search,
  ChevronDown,
  Check,
  LayoutGrid,
  Trash2,
  Cloud,
  Loader2
} from 'lucide-react';

const INITIAL_WORKSPACES: Workspace[] = [
  {
    id: 'ws-1',
    name: 'My Board',
    color: '#007AFF',
    cards: []
  }
];

const TAB_COLORS = [
  '#007AFF', // Blue
  '#34C759', // Green
  '#FF9500', // Orange
  '#FF2D55', // Red
  '#AF52DE', // Purple
  '#5856D6', // Indigo
  '#8E8E93', // Gray
];

export default function App() {
  const [workspaces, setWorkspaces] = useState<Workspace[]>(INITIAL_WORKSPACES);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('ws-1');

  // Tools & State
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');

  // Drawer & UI
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const isLoadedRef = useRef(false);

  // Undo/Redo Stacks
  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- FIREBASE INTEGRATION ---
  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      const savedData = await loadWorkspacesFromFirestore();
      if (savedData && savedData.length > 0) {
        setWorkspaces(savedData);
        const hasActive = savedData.find(w => w.id === activeWorkspaceId);
        if (!hasActive) {
          setActiveWorkspaceId(savedData[0].id);
        }
      }
      isLoadedRef.current = true;
      setIsLoading(false);
    };
    init();
  }, []);

  useEffect(() => {
    if (!isLoadedRef.current) return;
    setIsSaving(true);
    const handler = setTimeout(() => {
      saveWorkspacesToFirestore(workspaces).then(() => setIsSaving(false));
    }, 1000); 
    return () => clearTimeout(handler);
  }, [workspaces]);

  // --- Core Logic ---

  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  const updateCards = (newCards: CardData[]) => {
    // Push to history before updating
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]); // Keep last 20
    setFuture([]); // Clear redo stack

    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: newCards } : w
    ));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(prev => prev.slice(0, -1));

    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: previous } : w
    ));
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(prev => prev.slice(1));

    setWorkspaces(workspaces.map(w => 
      w.id === activeWorkspaceId ? { ...w, cards: next } : w
    ));
  };

  // Keyboard Shortcuts for Tools
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) return;

      if (e.key.toLowerCase() === 'v') setActiveTool('SELECT');
      if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      if (e.key.toLowerCase() === 't') setActiveTool('TEXT');
      if (e.key.toLowerCase() === 'n') setActiveTool('STICKY');
      if (e.key.toLowerCase() === 'p') setActiveTool('PEN');
      if (e.key.toLowerCase() === 'm') setActiveTool('HIGHLIGHTER');
      if (e.key.toLowerCase() === 'e') setActiveTool('ERASER');
      if (e.key.toLowerCase() === 'l') setActiveTool('LASSO');

      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
        e.preventDefault();
        handleUndo();
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'y') {
        e.preventDefault();
        handleRedo();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [history, future, activeWorkspace]);

  // --- Layout Helpers (Same as before) ---
  const updateWorkspaceColor = (id: string, color: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, color } : w));
  };

  const updateWorkspaceName = (id: string, name: string) => {
    setWorkspaces(workspaces.map(w => w.id === id ? { ...w, name } : w));
  };

  const deleteWorkspace = (id: string) => {
    if (workspaces.length <= 1) return alert("Cannot delete the last workspace.");
    const newWorkspaces = workspaces.filter(w => w.id !== id);
    setWorkspaces(newWorkspaces);
    if (activeWorkspaceId === id) setActiveWorkspaceId(newWorkspaces[0].id);
    setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
      setColorPickerState(null);
    } else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const addCard = (type: CardType) => {
    const newCard: CardData = {
      id: `card-${Date.now()}`,
      type,
      x: window.innerWidth / 2 - 180 + (Math.random() * 40),
      y: window.innerHeight / 2 - 200 + (Math.random() * 40),
      width: type === CardType.ANALYTICS ? 400 : (type === CardType.GRID_PLANNER ? 320 : 360),
      height: type === CardType.GRID_PLANNER ? 500 : 200, 
      zIndex: 100,
      content: {}
    };
    updateCards([...activeWorkspace.cards, newCard]);
  };

  const addWorkspace = () => {
    const newWs: Workspace = {
      id: `ws-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    setWorkspaces([...workspaces, newWs]);
    setActiveWorkspaceId(newWs.id);
  };

  const frequentTools = [
    { 
      id: 'post', 
      label: 'Social Post', 
      desc: 'Create social content', 
      icon: <FileImage size={24} />, 
      iconColor: 'text-purple-600',
      bg: 'bg-purple-50',
      action: () => addCard(CardType.POST)
    },
    { 
      id: 'grid', 
      label: 'Feed Planner', 
      desc: 'Visual monthly calendar', 
      icon: <LayoutGrid size={24} />, 
      iconColor: 'text-blue-600',
      bg: 'bg-blue-50',
      action: () => addCard(CardType.GRID_PLANNER)
    },
  ];

  const integrationTools = [
    { 
      id: 'pinterest', 
      label: 'Pinterest', 
      desc: 'Inspiration moodboard', 
      icon: <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor"><path d="M12.017 0C5.396 0 .029 5.367.029 11.987c0 5.079 3.158 9.417 7.618 11.162-.105-.949-.199-2.403.041-3.439.219-.937 1.406-5.957 1.406-5.957s-.359-.72-.359-1.781c0-1.663.967-2.911 2.168-2.911 1.024 0 1.518.769 1.518 1.688 0 1.029-.653 2.567-.992 3.992-.285 1.193.6 2.165 1.775 2.165 2.128 0 3.768-2.245 3.768-5.487 0-2.861-2.063-4.869-5.008-4.869-3.41 0-5.409 2.562-5.409 5.199 0 1.033.394 2.143.889 2.741.099.12.112.225.085.345-.09.375-.293 1.199-.334 1.363-.053.225-.172.271-.399.165-1.487-.695-2.419-2.875-2.419-4.629 0-3.773 2.749-7.253 7.951-7.253 4.173 0 7.41 2.967 7.41 6.923 0 4.133-2.607 7.462-6.233 7.462-1.214 0-2.354-.629-2.758-1.379l-.749 2.848c-.269 1.045-1.004 2.352-1.498 3.146 1.123.345 2.306.535 3.55.535 6.607 0 11.985-5.365 11.985-11.987C23.97 5.367 18.62 0 12.017 0z"/></svg>,
      color: 'bg-red-100 text-[#E60023]',
      tag: 'NEW',
      action: () => addCard(CardType.PINTEREST)
    }
  ];

  const filterItem = (item: any) => item.label.toLowerCase().includes(searchTerm.toLowerCase());

  if (isLoading) {
    return (
      <div className="w-full h-screen flex flex-col items-center justify-center bg-[#F2F2F7] text-gray-400">
        <Loader2 size={32} className="animate-spin mb-4 text-[#007AFF]" />
        <p className="text-[13px] font-medium">Loading Workspace...</p>
      </div>
    );
  }

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">
      <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 backdrop-blur border border-black/5 shadow-sm transition-opacity duration-300 ${isSaving ? 'opacity-100' : 'opacity-0'}`}>
        <Cloud size={14} className="text-[#007AFF]" />
        <span className="text-[11px] font-semibold text-gray-500">Saving...</span>
      </div>

      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
          activeTool={activeTool}
          onToolUsed={() => setActiveTool('SELECT')}
        />
      </div>

      {/* Tools Dock */}
      <ToolsDock 
        activeTool={activeTool} 
        onToolChange={setActiveTool} 
        canUndo={history.length > 0}
        canRedo={future.length > 0}
        onUndo={handleUndo}
        onRedo={handleRedo}
      />

      {/* (Keep existing Drawer & Spreadsheet Navigation logic...) */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button onClick={() => setIsDrawerOpen(true)} className="relative w-14 h-14 rounded-full group transition-all duration-500 hover:scale-110 active:scale-95 shadow-2xl">
           <div className="absolute -inset-[2px] rounded-full overflow-hidden z-0"><div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300%] h-[300%] bg-[conic-gradient(from_0deg,transparent_0_340deg,rgba(255,255,255,1)_360deg)] animate-[spin_4s_linear_infinite] opacity-60" /></div>
           <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-md border border-white/60 flex items-center justify-center z-10 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9)]">
              <Plus size={26} strokeWidth={1} className="text-gray-600 group-hover:text-gray-900 transition-colors duration-300" />
           </div>
        </button>
      </div>

      <div className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} onMouseLeave={() => setIsDrawerOpen(false)}>
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input type="text" placeholder="Search all nodes" className="w-full bg-gray-50 border border-gray-200 rounded-xl pl-10 pr-4 py-2.5 text-[15px] focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            <div className="p-5 space-y-8">
              {(!searchTerm || frequentTools.some(filterItem)) && (
                <div className="space-y-3">
                  <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Frequently Used</h3>
                  <div className="grid grid-cols-2 gap-3">
                    {frequentTools.filter(filterItem).map(tool => (
                      <button key={tool.id} onClick={tool.action} className="flex flex-col items-start p-4 rounded-2xl bg-white border border-gray-200 hover:border-gray-300 hover:shadow-md transition-all active:scale-[0.98] text-left group">
                        <div className={`w-10 h-10 rounded-xl ${tool.bg} ${tool.iconColor} flex items-center justify-center mb-3 group-hover:scale-110 transition-transform`}>{tool.icon}</div>
                        <div className="font-semibold text-gray-900 text-[14px] leading-tight mb-1">{tool.label}</div>
                        <div className="text-[12px] text-gray-500 leading-snug line-clamp-2">{tool.desc}</div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
              {(!searchTerm || integrationTools.some(filterItem)) && (
                <div className="space-y-3">
                   <h3 className="text-[13px] font-semibold text-gray-400 uppercase tracking-wider pl-1">Integrations</h3>
                   <div className="space-y-1">
                      {integrationTools.filter(filterItem).map(tool => (
                        <button key={tool.id} onClick={tool.action} className="w-full flex items-center gap-4 p-3 rounded-xl hover:bg-gray-50 transition-colors group text-left">
                          <div className={`w-10 h-10 rounded-xl ${tool.color} flex items-center justify-center shadow-sm border border-black/5 flex-shrink-0 group-hover:scale-105 transition-transform`}>{tool.icon}</div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between mb-0.5"><span className="font-semibold text-gray-900 text-[14px]">{tool.label}</span></div>
                            <p className="text-[13px] text-gray-500 truncate">{tool.desc}</p>
                          </div>
                          <div className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity"><Plus size={16} /></div>
                        </button>
                      ))}
                   </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="absolute bottom-6 left-6 right-0 z-40 flex items-end justify-start pointer-events-none">
        <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-2 pl-2 pr-4 pointer-events-auto max-w-full">
          {workspaces.map(ws => {
            const isActive = activeWorkspaceId === ws.id;
            return (
              <div key={ws.id} className="relative group flex-shrink-0">
                <button onClick={() => setActiveWorkspaceId(ws.id)} className={`relative h-11 px-4 min-w-[100px] max-w-[180px] flex items-center gap-2.5 rounded-full transition-all duration-300 select-none bg-gradient-to-br from-white/90 via-white/60 to-white/30 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] ${isActive ? 'text-gray-900 font-bold scale-100 z-10 ring-1 ring-white/50' : 'text-gray-500 hover:text-gray-900 hover:scale-[1.02] active:scale-[0.98] z-0 opacity-70 hover:opacity-100'}`}>
                  <div className={`w-2 h-2 rounded-full shadow-sm transition-transform duration-300 border border-white/50 ${isActive ? 'scale-110' : 'scale-100 opacity-70'}`} style={{ backgroundColor: ws.color || '#8E8E93' }} />
                  <span className="truncate text-[13px] tracking-tight">{ws.name}</span>
                  {isActive && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="ml-auto p-1 -mr-1 rounded-full hover:bg-black/5 text-gray-400 cursor-pointer transition-colors"><ChevronDown size={12} strokeWidth={2.5} /></div>}
                </button>
              </div>
            );
          })}
          <button onClick={addWorkspace} className="h-11 w-11 ml-1 flex-shrink-0 rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-xl border border-white/60 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9),0_4px_10px_-2px_rgba(0,0,0,0.1)] flex items-center justify-center text-gray-500 hover:text-[#007AFF] hover:scale-110 active:scale-95 transition-all duration-300 pointer-events-auto"><Plus size={20} strokeWidth={2.5} /></button>
        </div>
      </div>

      {colorPickerState && (
        <div onClick={(e) => e.stopPropagation()} className="fixed bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] flex flex-col gap-3 w-56 animate-in fade-in zoom-in-95 duration-200 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
          <input type="text" className="w-full bg-white/50 border border-black/5 rounded-lg px-2.5 py-1.5 text-[13px] font-medium text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#007AFF]/20 transition-all" placeholder="Workspace Name" value={workspaces.find(w => w.id === colorPickerState.id)?.name || ''} onChange={(e) => updateWorkspaceName(colorPickerState.id, e.target.value)} autoFocus />
          <div>
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2 block px-1">Tab Color</span>
              <div className="grid grid-cols-7 gap-1.5">
                {TAB_COLORS.map(c => <button key={c} onClick={() => updateWorkspaceColor(colorPickerState.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
              </div>
          </div>
          <div className="h-px bg-black/5 w-full my-0.5"></div>
          <button onClick={() => deleteWorkspace(colorPickerState.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Workspace</span></button>
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/80 backdrop-blur-xl border-r border-b border-white/40 rotate-45 transform"></div>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { ToolType } from '../../types';
import { 
