    { id: 'PEN', icon: <PenTool size={18} />, label: 'Pen' },
    { id: 'HIGHLIGHTER', icon: <Highlighter size={18} />, label: 'Marker' },
    { id: 'ERASER', icon: <Eraser size={18} />, label: 'Eraser' },
