      desc: 'Inspiration moodboard', 
      icon: <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor"><path d="M12.017 0C5.396 0 .029 5.367.029 11.987c0 5.079 3.158 9.417 7.618 11.162-.105-.949-.199-2.403.041-3.439.219-.937 1.406-5.957 1.406-5.957s-.359-.72-.359-1.781c0-1.663.967-2.911 2.168-2.911 1.024 0 1.518.769 1.518 1.688 0 1.029-.653 2.567-.992 3.992-.285 1.193.6 2.165 1.775 2.165 2.128 0 3.768-2.245 3.768-5.487 0-2.861-2.063-4.869-5.008-4.869-3.41 0-5.409 2.562-5.409 5.199 0 1.033.394 2.143.889 2.741.099.12.112.225.085.345-.09.375-.293 1.199-.334 1.363-.053.225-.172.271-.399.165-1.487-.695-2.419-2.875-2.419-4.629 0-3.773 2.749-7.253 7.951-7.253 4.173 0 7.41 2.967 7.41 6.923 0 4.133-2.607 7.462-6.233 7.462-1.214 0-2.354-.629-2.758-1.379l-.749 2.848c-.269 1.045-1.004 2.352-1.498 3.146 1.123.345 2.306.535 3.55.535 6.607 0 11.985-5.365 11.985-11.987C23.97 5.367 18.62 0 12.017 0z"/></svg>,
      color: 'bg-red-100 text-[#E60023]',
      tag: 'NEW',
      action: () => addCard(CardType.PINTEREST)
    }
  ];

  const filterItem = (item: any) => item.label.toLowerCase().includes(searchTerm.toLowerCase());

  if (isLoading) {
    return (
      <div className="w-full h-screen flex flex-col items-center justify-center bg-[#F2F2F7] text-gray-400">
        <Loader2 size={32} className="animate-spin mb-4 text-[#007AFF]" />
        <p className="text-[13px] font-medium">Loading Workspace...</p>
      </div>
    );
  }

  const isDrawingTool = ['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool);

  return (
    <div className="w-full h-screen relative overflow-hidden text-[#1C1C1E] bg-[#F2F2F7]">
      {/* Saving Indicator */}
      <div className={`fixed top-6 right-48 z-50 flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/80 backdrop-blur border border-black/5 shadow-sm transition-opacity duration-300 ${isSaving ? 'opacity-100' : 'opacity-0'}`}>
        <Cloud size={14} className="text-[#007AFF]" />
        <span className="text-[11px] font-semibold text-gray-500">Saving...</span>
      </div>

      {/* Top Right Bar: Scale + Undo/Redo */}
      <div className="fixed top-6 right-6 z-[50] flex items-center gap-2 no-drag">
         <div className="flex items-center p-1 bg-white/90 backdrop-blur-xl border border-white/40 rounded-xl shadow-sm ring-1 ring-black/5">
            {/* Scale Indicator */}
            <div className="px-3 text-[13px] font-mono font-medium text-gray-500 select-none w-[48px] text-center">
               {Math.round(scale * 100)}%
            </div>

            <div className="w-px h-5 bg-gray-200 mx-0.5"></div>

            {/* Undo/Redo Controls */}
            <button 
              onClick={handleUndo} 
              disabled={history.length === 0}
              className="w-9 h-9 rounded-lg flex items-center justify-center text-gray-500 hover:bg-gray-100 hover:text-gray-900 disabled:opacity-30 transition-colors"
              title="Undo (Ctrl+Z)"
            >
              <Undo2 size={18} />
            </button>
            <div className="w-px h-5 bg-gray-200 mx-0.5"></div>
            <button 
              onClick={handleRedo} 
              disabled={future.length === 0}
              className="w-9 h-9 rounded-lg flex items-center justify-center text-gray-500 hover:bg-gray-100 hover:text-gray-900 disabled:opacity-30 transition-colors"
              title="Redo (Ctrl+Y)"
            >
              <Redo2 size={18} />
            </button>
         </div>
      </div>

      <div className="absolute inset-0 z-0">
        <Canvas 
          cards={activeWorkspace.cards}
          onCardsChange={updateCards}
          activeTool={activeTool}
          onToolUsed={() => setActiveTool('SELECT')}
          scale={scale}
          onScaleChange={setScale}
          isSpacePressed={isSpacePressed}
        />
      </div>

      {/* Drawing Toolbar */}
      {isDrawingTool && (
        <DrawingToolbar 
          activeTool={activeTool} 
          onToolChange={setActiveTool} 
          onClose={() => setActiveTool('SELECT')}
        />
      )}

      {/* Menu Trigger (Top Left) */}
      <div 
        className={`fixed top-0 left-0 z-40 w-32 h-32 flex items-start justify-start p-6 transition-all duration-300 ${isDrawerOpen ? '-translate-x-full opacity-0 pointer-events-none' : 'translate-x-0 opacity-100'}`}
        onMouseEnter={() => setIsDrawerOpen(true)}
      >
        <button onClick={() => setIsDrawerOpen(true)} className="relative w-14 h-14 rounded-full group transition-all duration-500 hover:scale-110 active:scale-95 shadow-2xl">
           <div className="absolute -inset-[2px] rounded-full overflow-hidden z-0"><div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300%] h-[300%] bg-[conic-gradient(from_0deg,transparent_0_340deg,rgba(255,255,255,1)_360deg)] animate-[spin_4s_linear_infinite] opacity-60" /></div>
           <div className="absolute inset-[1px] rounded-full bg-gradient-to-br from-white/80 via-white/40 to-white/10 backdrop-blur-md border border-white/60 flex items-center justify-center z-10 shadow-[inset_0_1px_4px_rgba(255,255,255,0.9)]">
              <Plus size={26} strokeWidth={1} className="text-gray-600 group-hover:text-gray-900 transition-colors duration-300" />
           </div>
        </button>
      </div>

      {/* Drawer Menu */}
      <div className={`fixed inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} onMouseLeave={() => setIsDrawerOpen(false)}>
        {/* ... Drawer Content ... */}
        <div className="w-[340px] h-full bg-white shadow-2xl flex flex-col border-r border-gray-200">
          <div className="p-5 border-b border-gray-100 bg-white z-10">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
