import React, { useRef, useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Position, GridPlannerContent, ToolType, StrokePoint } from '../types';
import { PostCard } from './cards/PostCard';
import { AiStrategyCard } from './cards/AiStrategyCard';
import { AnalyticsCard } from './cards/AnalyticsCard';
import { GridPlannerCard } from './cards/GridPlannerCard';
import { PinterestCard } from './cards/PinterestCard';
import { StrokeCard } from './cards/StrokeCard';
import { TextCard } from './cards/TextCard';
import { StickyCard } from './cards/StickyCard';

interface CanvasProps {
  cards: CardData[];
  onCardsChange: (cards: CardData[]) => void;
  activeTool: ToolType;
  onToolUsed: () => void;
  scale: number;
  onScaleChange: React.Dispatch<React.SetStateAction<number>>;
  isSpacePressed?: boolean;
}

const GRID_HEADER_HEIGHT = 132; 
const GRID_PADDING = 20;
const GRID_GAP = 8;

export const Canvas: React.FC<CanvasProps> = ({ 
  cards, 
  onCardsChange, 
  activeTool, 
  onToolUsed, 
  scale, 
  onScaleChange,
  isSpacePressed = false
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });

  // Interaction States
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState<Position>({ x: 0, y: 0 });

  // Selection States
  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [selectionBox, setSelectionBox] = useState<{ start: Position, current: Position } | null>(null);

  const [draggingCardId, setDraggingCardId] = useState<string | null>(null);

  // Drawing States
  const [currentStroke, setCurrentStroke] = useState<StrokePoint[]>([]);
  const [isDrawing, setIsDrawing] = useState(false);

  // Lasso State
  const [lassoPath, setLassoPath] = useState<Position[]>([]);

  // Snapping / Grid Logic
  const [hoveredGridId, setHoveredGridId] = useState<string | null>(null);
  const [hoveredSlotIndex, setHoveredSlotIndex] = useState<number | null>(null);

  // --- Infinite Background Logic ---
  const gridLayers = useMemo(() => {
    const layers = [];
    const baseSpacing = 40; 
    const logScale = Math.log10(scale);
    const currentPower = Math.floor(logScale);

    for (let i = -1; i <= 1; i++) {
      const power = -currentPower + i; 
      const worldSpacing = baseSpacing * Math.pow(10, power);
      const visualSpacing = worldSpacing * scale;
      let rawOpacity = 0;

      if (visualSpacing >= 15 && visualSpacing <= 250) {
        if (visualSpacing < 50) {
           rawOpacity = (visualSpacing - 15) / 35;
        } else if (visualSpacing > 100) {
           rawOpacity = 1 - (visualSpacing - 100) / 150;
        } else {
           rawOpacity = 1;
        }
      }
      const finalOpacity = Math.max(0, Math.min(1, rawOpacity)) * 0.3;
      if (finalOpacity > 0.01) {
        layers.push({ spacing: visualSpacing, opacity: finalOpacity, key: `grid-layer-${power}` });
      }
    }
    return layers;
  }, [scale]);

  const handleWheel = (e: WheelEvent) => {
    e.preventDefault();
    if (e.ctrlKey || e.metaKey) {
      // Zoom
      const s = Math.exp(-e.deltaY * 0.005);
      const newScale = Math.min(Math.max(0.05, scale * s), 10);
      onScaleChange(newScale);
    } else {
      // Pan
      setPan(prev => ({ x: prev.x - e.deltaX, y: prev.y - e.deltaY }));
    }
  };

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', handleWheel, { passive: false });
    return () => el.removeEventListener('wheel', handleWheel);
  }, [scale]); // Re-bind when scale changes to get correct values if needed, mostly for zoom

  // --- Coordinate Utilities ---

  const screenToWorld = (sx: number, sy: number) => {
    return {
        x: (sx - pan.x) / scale,
        y: (sy - pan.y) / scale
    };
  };

  // --- SELECTION HELPERS ---

  const handleSelectionAction = (id: string, options?: { toggle?: boolean, keepOthers?: boolean }) => {
      if (options?.toggle) {
          if (selectedCardIds.includes(id)) {
              setSelectedCardIds(prev => prev.filter(cId => cId !== id));
          } else {
              setSelectedCardIds(prev => [...prev, id]);
          }
      } else if (options?.keepOthers) {
          if (!selectedCardIds.includes(id)) {
              setSelectedCardIds(prev => [...prev, id]);
          }
      } else {
          // Exclusive Select
          setSelectedCardIds([id]);
      }
  };

  // --- MOUSE HANDLERS ---

  const handleMouseDown = (e: React.MouseEvent) => {
    const worldPos = screenToWorld(e.clientX, e.clientY);

    // 1. Panning Priority (Space, Middle Click, or Pan Tool)
    if (isSpacePressed || activeTool === 'PAN' || e.button === 1) {
        setIsPanning(true);
        setLastMousePos({ x: e.clientX, y: e.clientY });
        return;
    }

    // 2. Tool Logic
    if (activeTool === 'SELECT') {
        if (e.button === 0) { // Left Click
            // Check if clicking background (cards stop propagation)
            if (!e.shiftKey) {
               setSelectedCardIds([]); // Clear selection on background click
            }
            // Start Marquee Selection
            setSelectionBox({ 
                start: { x: e.clientX, y: e.clientY }, 
                current: { x: e.clientX, y: e.clientY } 
            });
        }
    } else if (activeTool === 'TEXT') {
        // Create Text Object
        const newCard: CardData = {
            id: `text-${Date.now()}`,
            type: CardType.TEXT,
            x: worldPos.x,
            y: worldPos.y,
            width: 300,
            height: 50,
            zIndex: 100,
            content: { text: 'Type something...', fontSize: 24, fontFamily: 'Inter', textAlign: 'left', color: '#1C1C1E' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardIds([newCard.id]);
        onToolUsed(); 
    } else if (activeTool === 'STICKY') {
        const newCard: CardData = {
            id: `sticky-${Date.now()}`,
            type: CardType.STICKY,
            x: worldPos.x - 100, 
            y: worldPos.y - 100,
            width: 200,
            height: 200,
            zIndex: 100,
            content: { text: '', color: '#FFD966' }
        };
        onCardsChange([...cards, newCard]);
        setSelectedCardIds([newCard.id]);
        onToolUsed();
    } else if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
        setIsDrawing(true);
        setCurrentStroke([{ x: worldPos.x, y: worldPos.y }]);
    } else if (activeTool === 'ERASER') {
        setIsDrawing(true);
    } else if (activeTool === 'LASSO') {
        setIsDrawing(true);
        setLassoPath([{ x: worldPos.x, y: worldPos.y }]);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    const worldPos = screenToWorld(e.clientX, e.clientY);

    // Pan Canvas
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setPan(prev => ({ x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
      return;
    }

    // Marquee Selection Update
    if (selectionBox) {
        setSelectionBox(prev => ({ ...prev!, current: { x: e.clientX, y: e.clientY } }));

        // No live selection state update to avoid heavy react rendering loops during drag.
        // We calculate final selection on MouseUp.
    }

    // Drawing Update
    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            setCurrentStroke(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'LASSO') {
            setLassoPath(prev => [...prev, { x: worldPos.x, y: worldPos.y }]);
        } else if (activeTool === 'ERASER') {
            const ERASER_RADIUS = 20 / scale;
            const remainingCards = cards.filter(c => {
                if (c.type !== CardType.STROKE) return true;
                if (
                    worldPos.x < c.x - ERASER_RADIUS || worldPos.x > c.x + c.width + ERASER_RADIUS ||
                    worldPos.y < c.y - ERASER_RADIUS || worldPos.y > c.y + c.height + ERASER_RADIUS
                ) return true;

                const content = c.content;
                const points = content.points as StrokePoint[];
                return !points.some(p => {
                    const px = c.x + p.x;
                    const py = c.y + p.y;
                    const dist = Math.sqrt(Math.pow(px - worldPos.x, 2) + Math.pow(py - worldPos.y, 2));
                    return dist < ERASER_RADIUS;
                });
            });

            if (remainingCards.length !== cards.length) {
                onCardsChange(remainingCards);
            }
        }
    }
  };

  const handleMouseUp = (e: React.MouseEvent) => {
    // Finalize Marquee Selection
    if (selectionBox) {
        const startWorld = screenToWorld(selectionBox.start.x, selectionBox.start.y);
        const endWorld = screenToWorld(e.clientX, e.clientY);

        const minX = Math.min(startWorld.x, endWorld.x);
        const maxX = Math.max(startWorld.x, endWorld.x);
        const minY = Math.min(startWorld.y, endWorld.y);
        const maxY = Math.max(startWorld.y, endWorld.y);

        // Threshold to prevent micro-drags being counted as selection boxes
        if (Math.abs(maxX - minX) > 2 || Math.abs(maxY - minY) > 2) {
             const intersectingIds = cards.filter(c => {
                const cRight = c.x + c.width;
                const cBottom = c.y + c.height;
                // AABB Intersection: box min < card max AND box max > card min
                return (minX < cRight && maxX > c.x && minY < cBottom && maxY > c.y);
            }).map(c => c.id);

            if (e.shiftKey) {
                // Add unique ids
                const newSet = new Set([...selectedCardIds, ...intersectingIds]);
                setSelectedCardIds(Array.from(newSet));
            } else {
                setSelectedCardIds(intersectingIds);
            }
        }
        setSelectionBox(null);
    }

    if (isDrawing) {
        if (activeTool === 'PEN' || activeTool === 'HIGHLIGHTER') {
            if (currentStroke.length > 2) {
                const xs = currentStroke.map(p => p.x);
                const ys = currentStroke.map(p => p.y);
                const minX = Math.min(...xs);
                const minY = Math.min(...ys);
                const maxX = Math.max(...xs);
                const maxY = Math.max(...ys);
                const width = maxX - minX;
                const height = maxY - minY;

                const relativePoints = currentStroke.map(p => ({
                    x: p.x - minX,
                    y: p.y - minY,
                    p: p.p
                }));

                const newCard: CardData = {
                    id: `stroke-${Date.now()}`,
                    type: CardType.STROKE,
                    x: minX,
                    y: minY,
                    width: Math.max(width, 1), 
                    height: Math.max(height, 1),
                    zIndex: 50,
                    content: {
                        points: relativePoints,
                        color: activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E',
                        width: activeTool === 'HIGHLIGHTER' ? 20 : 4,
                        isHighlighter: activeTool === 'HIGHLIGHTER'
                    }
                };
                onCardsChange([...cards, newCard]);
            }
        } else if (activeTool === 'LASSO') {
            if (lassoPath.length > 2) {
                const lx = lassoPath.map(p => p.x);
                const ly = lassoPath.map(p => p.y);
                const minX = Math.min(...lx);
                const minY = Math.min(...ly);
                const maxX = Math.max(...lx);
                const maxY = Math.max(...ly);

                const hit = cards.filter(c => 
                    c.x >= minX && c.x + c.width <= maxX &&
                    c.y >= minY && c.y + c.height <= maxY
                ).map(c => c.id);

                if (hit.length > 0) setSelectedCardIds(hit);
            }
        }
    }

    setIsPanning(false);
    setIsDrawing(false);
    setCurrentStroke([]);
    setLassoPath([]);
    setDraggingCardId(null);
    setHoveredGridId(null);
    setHoveredSlotIndex(null);
  };

  // --- CRUD Handlers ---

  const updateCardPosition = (id: string, x: number, y: number) => {
    const movedCard = cards.find(c => c.id === id);
    if (!movedCard) return; 

    // Calculate Delta
    const dx = x - movedCard.x;
    const dy = y - movedCard.y;

    if (draggingCardId !== id) setDraggingCardId(id);

    // If the moved card is part of the selection, move the whole group
    if (selectedCardIds.includes(id)) {
        const newCards = cards.map(c => {
            if (selectedCardIds.includes(c.id)) {
                return { ...c, x: c.x + dx, y: c.y + dy };
            }
            return c;
        });
        onCardsChange(newCards);
    } else {
        // Move single card
        onCardsChange(cards.map(c => c.id === id ? { ...c, x, y } : c));
    }
  };

  const updateCardContent = (id: string, content: any) => {
    onCardsChange(cards.map(c => c.id === id ? { ...c, content } : c));
  };

  const handleDeleteCard = (id: string) => {
    if (selectedCardIds.includes(id)) {
        onCardsChange(cards.filter(c => !selectedCardIds.includes(c.id)));
        setSelectedCardIds([]);
    } else {
        onCardsChange(cards.filter(c => c.id !== id));
        if (selectedCardIds.includes(id)) {
            setSelectedCardIds(prev => prev.filter(cid => cid !== id));
        }
    }
  };

  const bringToFront = (id: string, options?: { toggle?: boolean, keepOthers?: boolean }) => {
    // Handle Selection Logic
    handleSelectionAction(id, options);

    // Z-Index Logic
    const maxZ = Math.max(...cards.map(c => c.zIndex || 1));
    onCardsChange(cards.map(c => c.id === id ? { ...c, zIndex: maxZ + 1 } : c));
  };

  // --- Keyboard Shortcuts ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.key === 'Delete' || e.key === 'Backspace') {
          if (selectedCardIds.length > 0) {
              onCardsChange(cards.filter(c => !selectedCardIds.includes(c.id)));
              setSelectedCardIds([]);
          }
      }
      if (e.key === 'Escape') {
          setSelectedCardIds([]);
          setSelectionBox(null);
          setIsDrawing(false);
      }
      if ((e.metaKey || e.ctrlKey) && e.key === 'a') {
          e.preventDefault();
          setSelectedCardIds(cards.map(c => c.id));
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedCardIds, cards]);

  const renderCard = (card: CardData) => {
    const commonProps = {
      key: card.id,
      card,
      isSelected: selectedCardIds.includes(card.id),
      onSelect: bringToFront,
      onMove: updateCardPosition,
      onDelete: handleDeleteCard,
      onUpdateContent: updateCardContent,
      zoomScale: scale
    };

    switch (card.type) {
      case CardType.POST:
        return <PostCard {...commonProps} isLinked={false} />;
      case CardType.STRATEGY_AI:
        return <AiStrategyCard {...commonProps} />;
      case CardType.ANALYTICS:
        return <AnalyticsCard {...commonProps} />;
      case CardType.GRID_PLANNER:
        return (
          <GridPlannerCard 
            {...commonProps} 
            allCards={cards}
            onUnlink={()=>{}} onLinkPost={()=>{}} onSwapSlots={()=>{}}
            hoveredSlotIndex={null}
          />
        );
      case CardType.PINTEREST:
        return <PinterestCard {...commonProps} />;
      case CardType.TEXT:
        return <TextCard {...commonProps} />;
      case CardType.STICKY:
        return <StickyCard {...commonProps} />;
      case CardType.STROKE:
        return <StrokeCard {...commonProps} />;
      default:
        return <PostCard {...commonProps} />;
    }
  };

  // Group Bounding Box
  const groupBounds = useMemo(() => {
      if (selectedCardIds.length <= 1) return null;
      const selectedCards = cards.filter(c => selectedCardIds.includes(c.id));
      if (selectedCards.length === 0) return null;

      const minX = Math.min(...selectedCards.map(c => c.x));
      const minY = Math.min(...selectedCards.map(c => c.y));
      const maxX = Math.max(...selectedCards.map(c => c.x + c.width));
      const maxY = Math.max(...selectedCards.map(c => c.y + c.height));

      return { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
  }, [selectedCardIds, cards]);

  // If panning mode is active, content should ignore pointer events to let drag pass through
  const isPanMode = isSpacePressed || activeTool === 'PAN' || isPanning;

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full bg-[#f3f4f6] relative overflow-hidden ${isPanMode ? 'cursor-grab active:cursor-grabbing' : (activeTool === 'SELECT' ? 'cursor-default' : 'cursor-crosshair')}`}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* Background Grid */}
      {gridLayers.map((layer) => (
        <div 
          key={layer.key}
          className="absolute inset-0 pointer-events-none"
          style={{
            backgroundSize: `${layer.spacing}px ${layer.spacing}px`,
            backgroundPosition: `${pan.x}px ${pan.y}px`,
            backgroundImage: `radial-gradient(circle, rgba(156, 163, 175, ${layer.opacity}) 1.5px, transparent 1.5px)`,
            opacity: 1 
          }}
        />
      ))}

      {/* Content Container */}
      <div 
        className="absolute origin-top-left transition-transform duration-75 ease-out"
        style={{
          transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`,
          // IMPORTANT: If panning, cards should be transparent to mouse events so drag works everywhere
          pointerEvents: isPanMode ? 'none' : 'auto'
        }}
      >
        {cards.map(renderCard)}

        {/* Group Selection Box */}
        {groupBounds && (
            <div 
                className="absolute border border-[#007AFF] pointer-events-none z-[60]"
                style={{
                    left: groupBounds.x,
                    top: groupBounds.y,
                    width: groupBounds.width,
                    height: groupBounds.height,
                }}
            />
        )}
      </div>

      {/* Interaction Layers */}
      <div className="absolute inset-0 pointer-events-none">
          <svg className="w-full h-full overflow-visible">
              {isDrawing && currentStroke.length > 0 && (
                  <path 
                    d={`M ${currentStroke.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')}`}
                    stroke={activeTool === 'HIGHLIGHTER' ? '#FFE500' : '#1C1C1E'}
                    strokeWidth={(activeTool === 'HIGHLIGHTER' ? 20 : 4) * scale}
                    fill="none"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeOpacity={activeTool === 'HIGHLIGHTER' ? 0.5 : 1}
                  />
              )}
              {isDrawing && activeTool === 'LASSO' && lassoPath.length > 0 && (
                   <path 
                   d={`M ${lassoPath.map(p => `${(p.x * scale) + pan.x} ${(p.y * scale) + pan.y}`).join(' L ')} Z`}
                   stroke="#007AFF"
                   strokeWidth={2}
                   fill="rgba(0, 122, 255, 0.1)"
                   strokeDasharray="5,5"
                 />
              )}
          </svg>

          {/* Marquee Selection Box */}
          {selectionBox && (
              <div 
                  className="absolute bg-[#007AFF]/10 border border-[#007AFF] z-[9999]"
                  style={{
                      left: Math.min(selectionBox.start.x, selectionBox.current.x),
                      top: Math.min(selectionBox.start.y, selectionBox.current.y),
                      width: Math.abs(selectionBox.current.x - selectionBox.start.x),
                      height: Math.abs(selectionBox.current.y - selectionBox.start.y),
                  }}
              />
          )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { CardData, CardType } from '../../types';
import { Maximize2, Minimize2 } from 'lucide-react';

interface BaseCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string, options?: { toggle?: boolean; keepOthers?: boolean }) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  zoomScale: number;
  children: React.ReactNode;
  title?: string;
  accentColor?: string;
  icon?: React.ReactNode;
  variant?: 'default' | 'minimal' | 'sticky'; 
  className?: string;
}

export const BaseCard: React.FC<BaseCardProps> = ({
  card,
  isSelected,
  onSelect,
  onMove,
  onDelete, 
  zoomScale,
  children,
  title,
  icon,
  variant = 'default',
  className = ''
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const hasMovedRef = useRef(false);

  const isFixedLayout = [CardType.GRID_PLANNER, CardType.ANALYTICS, CardType.PERSONA].includes(card.type);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Allow Middle Click to bubble to Canvas for Panning
    if (e.button === 1 || isFullscreen) return;

    // Stop propagation so we don't trigger Canvas Marquee or Deselect
    e.stopPropagation();

    // Selection Logic
    if (e.shiftKey) {
        // Shift + Click: Toggle selection
        onSelect(card.id, { toggle: true });
    } else {
        if (!isSelected) {
            // New selection: Clear others immediately
            onSelect(card.id, { keepOthers: false });
        } else {
            // Already selected: Keep group selected (might be start of a group drag)
            onSelect(card.id, { keepOthers: true }); 
        }
    }

    const target = e.target as HTMLElement;
    const isInteractive = 
      target.tagName === 'INPUT' || 
      target.tagName === 'TEXTAREA' || 
      target.isContentEditable ||
      target.tagName === 'BUTTON' || 
      target.closest('button') ||
      target.closest('.no-drag');

    if (!isInteractive) {
      setIsDragging(true);
      hasMovedRef.current = false;
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const dx = (e.clientX - dragStartRef.current.x) / zoomScale;
      const dy = (e.clientY - dragStartRef.current.y) / zoomScale;

      if (Math.abs(dx) > 1 || Math.abs(dy) > 1) {
          hasMovedRef.current = true;
      }

      onMove(card.id, card.x + dx, card.y + dy);
      dragStartRef.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = (e: MouseEvent) => {
      if (isDragging) {
        // If we didn't drag, didn't shift-click, and are already selected...
        // This is a "Click-Through" on a group member. Now we deselect the others.
        if (!hasMovedRef.current && isSelected && !e.shiftKey) {
            onSelect(card.id, { keepOthers: false });
        }
        setIsDragging(false);
      }
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, card.id, card.x, card.y, onMove, zoomScale, isSelected, onSelect]);

  const toggleFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsFullscreen(!isFullscreen);
  };

  const getSelectionStyles = () => {
    if (isFullscreen) return 'fixed inset-0 z-[9999] w-full h-full rounded-none bg-white overflow-auto';

    // Variant-based styling
    if (variant === 'minimal') {
      return `absolute select-none ${isSelected ? 'ring-1 ring-blue-500/50' : 'hover:ring-1 hover:ring-blue-200/50'}`;
    }

    if (variant === 'sticky') {
      return `absolute flex flex-col transition-shadow duration-200 cursor-grab active:cursor-grabbing ${isSelected ? 'shadow-2xl ring-2 ring-blue-500 z-50' : 'shadow-md hover:shadow-lg z-10'}`;
    }

    // Default Cards
    const colors = {
      [CardType.POST]: { ring: 'ring-purple-500', hover: 'hover:ring-purple-300' },
      [CardType.STRATEGY_AI]: { ring: 'ring-indigo-500', hover: 'hover:ring-indigo-300' },
      [CardType.ANALYTICS]: { ring: 'ring-emerald-500', hover: 'hover:ring-emerald-300' },
      [CardType.PERSONA]: { ring: 'ring-orange-500', hover: 'hover:ring-orange-300' },
      [CardType.GRID_PLANNER]: { ring: 'ring-blue-400', hover: 'hover:ring-blue-300' },
      [CardType.PINTEREST]: { ring: 'ring-red-500', hover: 'hover:ring-red-300' }
    }[card.type] || { ring: 'ring-gray-400', hover: 'hover:ring-gray-300' };

    const base = "flex flex-col bg-white transition-all duration-300 ease-[cubic-bezier(0.2,0.8,0.2,1)] cursor-grab active:cursor-grabbing absolute";

    if (isSelected) {
      return `${base} shadow-[0_20px_40px_-12px_rgba(0,0,0,0.12)] z-50 scale-[1.005] ring-2 ring-offset-0 ${colors.ring}`;
    } else {
      return `${base} shadow-[0_4px_12px_-4px_rgba(0,0,0,0.08)] z-10 hover:shadow-[0_12px_24px_-8px_rgba(0,0,0,0.1)] hover:ring-2 hover:ring-offset-0 ${colors.hover}`;
    }
  };

  const cardContent = (
    <div
      ref={containerRef}
      className={`${getSelectionStyles()} ${className}`}
      style={!isFullscreen ? {
        left: card.x,
        top: card.y,
        width: card.width,
        height: isFixedLayout ? card.height : 'auto', 
        minHeight: isFixedLayout ? undefined : card.height,
        borderRadius: variant === 'default' ? '24px' : undefined,
      } : {}}
      onMouseDown={handleMouseDown} 
      onClick={(e) => e.stopPropagation()}
    >
      {variant === 'default' && (
        <div className={`flex items-center justify-between px-5 pt-5 pb-2 rounded-t-[24px] select-none shrink-0`}>
          <div className="flex items-center gap-2.5 text-gray-900">
            <span className="text-gray-400">{icon}</span>
            <span className="text-[13px] font-semibold tracking-tight text-gray-500">{title}</span>
          </div>
          <button 
            onClick={toggleFullscreen} 
            className="w-6 h-6 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-gray-600 transition-colors"
          >
            {isFullscreen ? <Minimize2 size={14} /> : <Maximize2 size={14} />}
          </button>
        </div>
      )}

      <div className={`flex-1 flex flex-col min-h-0 ${isFixedLayout ? 'overflow-hidden rounded-b-[24px]' : (variant === 'default' ? 'px-5 pb-5 overflow-visible' : '')}`}>
        {children}
      </div>

      {isSelected && (variant === 'default' || variant === 'sticky' || card.type === CardType.TEXT) && !isFullscreen && (
         <div className="absolute -bottom-3 -right-3 w-6 h-6 bg-white border border-gray-200 rounded-full shadow-md z-50 flex items-center justify-center cursor-nwse-resize group">
            <div className="w-2 h-2 rounded-full bg-blue-500 group-hover:scale-125 transition-transform" />
         </div>
      )}
    </div>
  );

  if (isFullscreen) {
    return createPortal(cardContent, document.body);
  }

  return cardContent;
};

export enum CardType {
  POST = 'POST',
  STRATEGY_AI = 'STRATEGY_AI',
  ANALYTICS = 'ANALYTICS',
  PERSONA = 'PERSONA',
  GRID_PLANNER = 'GRID_PLANNER',
  PINTEREST = 'PINTEREST',
  // New Creative Types
  TEXT = 'TEXT',
  STICKY = 'STICKY',
  STROKE = 'STROKE'
}

export type ToolType = 'SELECT' | 'PAN' | 'TEXT' | 'STICKY' | 'PEN' | 'HIGHLIGHTER' | 'ERASER' | 'LASSO';

export interface Position {
  x: number;
  y: number;
}

export interface TaskItem {
  id: string;
  text: string;
  done: boolean;
}

export interface TaskList {
  id: string;
  title: string;
  color: 'yellow' | 'blue' | 'red' | 'green' | 'gray';
  items: TaskItem[];
}

export interface MediaItem {
  id: string;
  type: 'image' | 'link' | 'video' | 'empty';
  url?: string;
  thumbnail?: string;
  sourceLink?: string;
}

export interface Comment {
  id: string;
  user: string;
  avatar: string;
  text: string;
  timestamp: string;
}

// --- Content Interfaces ---

export interface PostCardContent {
  sku?: string;
  title?: string;
  date?: string;
  caption?: string;
  references?: MediaItem[];
  finalAssets?: MediaItem[];
  taskLists?: TaskList[];
  comments?: Comment[];
  assignees?: string[];
  driveFolderId?: string;
  driveFolderUrl?: string;
  lastSynced?: string;
}

export interface GridConfig {
  month: number;
  year: number;
  logicType: 'frequency' | 'count';
  value: number;
}

export interface GridPlannerContent {
  title?: string;
  config: GridConfig;
  connections: { [slotIndex: number]: string };
}

export interface PinItem {
  id: string;
  imageUrl: string;
  link: string;
  description: string;
}

export interface PinterestCardContent {
  isConnected: boolean;
  username?: string;
  pins?: PinItem[];
