// New Creative Content Types

export type TextShape = 'none' | 'rectangle' | 'rounded' | 'pill' | 'diamond' | 'parallelogram';

export interface TextCardContent {
  text: string;
  fontSize: number;
  fontFamily: string;
  textAlign: 'left' | 'center' | 'right';
  color: string;
  highlightColor?: string; // Background color for shape/text
  isBold?: boolean;
  isItalic?: boolean;
  isUnderline?: boolean;
  shape?: TextShape;
  opacity?: number;
}

export interface StickyCardContent {
  text: string;
  color: string; // Background color (e.g. yellow, blue)
}

export interface StrokePoint {
  x: number;
  y: number;
  p?: number; // Pressure
}

export interface StrokeCardContent {
  points: StrokePoint[];
  color: string;
  width: number;
  isHighlighter: boolean;
}

export interface CardData {
  id: string;
  type: CardType;
  x: number;
  y: number;
  width: number;
  height: number;
  zIndex: number;
  content: PostCardContent | GridPlannerContent | PinterestCardContent | TextCardContent | StickyCardContent | StrokeCardContent | any;
}

export interface Workspace {
  id: string;
  name: string;
  cards: CardData[];
  color?: string;
}

export interface AppState {
  workspaces: Workspace[];
  activeWorkspaceId: string;
  scale: number;
  pan: Position;
}

import React, { useState, useEffect, useRef } from 'react';
import { BaseCard } from './BaseCard';
import { CardData, TextCardContent, TextShape } from '../../types';
import { 
  Bold, Italic, Underline, AlignLeft, AlignCenter, AlignRight, 
  ChevronDown, Type, Palette, Square, Circle, Diamond, PaintBucket,
  Minus, Plus, Type as TypeIcon
} from 'lucide-react';

// --- CONSTANTS ---

const FONT_FAMILIES = [
  { name: 'Inter', label: 'Inter' },
  { name: 'Roboto', label: 'Roboto' },
  { name: 'Open Sans', label: 'Open Sans' },
  { name: 'Playfair Display', label: 'Playfair' },
  { name: 'Montserrat', label: 'Montserrat' },
  { name: 'Lato', label: 'Lato' },
  { name: 'Merriweather', label: 'Merriweather' },
  { name: 'Comic Neue', label: 'Comic' },
  { name: 'Courier Prime', label: 'Mono' },
  { name: 'Abril Fatface', label: 'Display' },
];

const FONT_SIZES = [12, 14, 16, 18, 24, 32, 48, 64, 96, 128, 160];

const PALETTE = [
  '#000000', '#545454', '#737373', '#A6A6A6', '#D9D9D9', '#FFFFFF',
  '#E03E3E', '#D9730D', '#D9B310', '#0B6E99', '#0F7B6C', '#64473A',
  '#FFB8B8', '#FAE3B3', '#FFF6CC', '#D4ECF7', '#D3F5EF', '#EADBD6'
];

const SHAPES: { id: TextShape; icon: React.ReactNode; label: string }[] = [
  { id: 'none', icon: <Type size={14} />, label: 'None' },
  { id: 'rectangle', icon: <Square size={14} />, label: 'Rect' },
  { id: 'rounded', icon: <div className="w-3.5 h-3.5 border-2 border-current rounded-md" />, label: 'Soft' },
  { id: 'pill', icon: <div className="w-4 h-3 border-2 border-current rounded-full" />, label: 'Pill' },
  { id: 'diamond', icon: <Diamond size={14} />, label: 'Diamond' },
];

// --- SUB-COMPONENTS ---

const Dropdown = ({ 
  label, 
  value, 
  children, 
  width = 'w-48' 
}: { 
  label?: React.ReactNode, 
  value?: React.ReactNode, 
  children: React.ReactNode, 
  width?: string 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (ref.current && !ref.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="relative" ref={ref}>
      <button 
        onClick={(e) => { e.stopPropagation(); setIsOpen(!isOpen); }}
        className="flex items-center gap-1.5 px-2 py-1.5 hover:bg-gray-100 rounded-lg transition-colors text-gray-700 h-8"
      >
        {value || label}
        <ChevronDown size={10} className="text-gray-400" />
      </button>
      {isOpen && (
        <div 
          className={`absolute top-full mt-1 left-0 ${width} max-h-64 overflow-y-auto bg-white rounded-xl shadow-xl border border-gray-100 z-[200] p-1 animate-in fade-in zoom-in-95 duration-100 no-drag`}
          onMouseDown={(e) => e.stopPropagation()}
        >
          {children}
        </div>
      )}
    </div>
  );
};

const ColorPicker = ({ 
  color, 
  onChange, 
  icon 
}: { 
  color: string; 
  onChange: (c: string) => void; 
  icon: React.ReactNode;
}) => {
  return (
    <Dropdown 
      value={
        <div className="flex items-center gap-2">
           {icon}
           <div className="w-4 h-4 rounded-full border border-black/10 shadow-sm" style={{ backgroundColor: color === 'transparent' ? 'white' : color }}>
             {color === 'transparent' && <div className="w-full h-full border-r border-red-500 transform rotate-45 scale-125 opacity-50" />}
           </div>
        </div>
      }
      width="w-48"
    >
       <div className="p-2 grid grid-cols-6 gap-1.5">
          <button 
             onClick={() => onChange('transparent')}
             className={`w-6 h-6 rounded-md border border-gray-200 bg-white relative overflow-hidden hover:scale-110 transition-transform ${color === 'transparent' ? 'ring-2 ring-blue-500' : ''}`}
             title="Transparent"
          >
              <div className="absolute inset-0 border-r border-red-400 transform rotate-45" />
          </button>
          {PALETTE.map(c => (
             <button 
               key={c} 
               onClick={() => onChange(c)}
               className={`w-6 h-6 rounded-md border border-black/5 hover:scale-110 transition-transform shadow-sm ${color === c ? 'ring-2 ring-blue-500 ring-offset-1' : ''}`}
               style={{ backgroundColor: c }}
             />
          ))}
       </div>
    </Dropdown>
  );
};

interface TextCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  zoomScale: number;
}

export const TextCard: React.FC<TextCardProps> = (props) => {
  const { card, onUpdateContent, isSelected } = props;
  const content = card.content as TextCardContent;
  const editorRef = useRef<HTMLDivElement>(null);
  const [isEditing, setIsEditing] = useState(false);

  // Local state for font size input to allow typing
  const [localFontSize, setLocalFontSize] = useState<string>(content.fontSize?.toString() || "24");

  // Initialize defaults
  useEffect(() => {
    if (!content.fontFamily) {
        onUpdateContent(card.id, {
            ...content,
            fontSize: content.fontSize || 24,
            fontFamily: 'Inter',
            textAlign: 'left',
            color: '#1C1C1E',
            shape: 'none',
            highlightColor: 'transparent'
        });
    }
  }, []);

  useEffect(() => {
      setLocalFontSize(content.fontSize?.toString() || "24");
  }, [content.fontSize]);

  const handleBlur = () => {
    if (editorRef.current) {
        onUpdateContent(card.id, { ...content, text: editorRef.current.innerText });
    }
    setIsEditing(false);
  };

  const updateField = (key: keyof TextCardContent, value: any) => {
      onUpdateContent(card.id, { ...content, [key]: value });
  };

  const handleFontSizeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setLocalFontSize(e.target.value);
      const val = parseInt(e.target.value);
      if (!isNaN(val) && val > 0) {
          updateField('fontSize', val);
      }
  };

  // --- RENDERING HELPERS ---

  const getShapeStyles = () => {
      const base = "w-full h-full flex flex-col justify-center transition-all duration-200";
      const padding = content.shape !== 'none' ? 'px-6 py-4' : 'px-1 py-1';

      let shapeClass = '';
      switch (content.shape) {
          case 'rectangle': shapeClass = 'rounded-none'; break;
          case 'rounded': shapeClass = 'rounded-2xl'; break;
          case 'pill': shapeClass = 'rounded-full'; break;
          case 'diamond': shapeClass = ''; break; // Diamond handled via transform container if needed, or keeping simple
          case 'parallelogram': shapeClass = ''; break;
          default: shapeClass = ''; 
      }

      // Diamond logic is tricky with CSS only for variable text without cutting off. 
      // For MVP we stick to basic borders.

      return {
          className: `${base} ${shapeClass} ${padding}`,
          style: {
              backgroundColor: content.highlightColor || 'transparent',
              // Diamond simulation (simplified)
              transform: content.shape === 'diamond' ? 'rotate(0deg)' : 'none', 
          }
      };
  };

  const shapeStyles = getShapeStyles();

  return (
    <BaseCard {...props} variant="minimal">
      <div className="relative group min-w-[50px]">

        {/* --- RICH TEXT TOOLBAR --- */}
        {isSelected && (
            <div 
                className="absolute -top-16 left-1/2 -translate-x-1/2 flex items-center gap-1 p-1.5 bg-white rounded-xl shadow-[0_8px_30px_rgba(0,0,0,0.12)] border border-gray-100 z-[100] animate-in slide-in-from-bottom-2 fade-in duration-200 no-drag whitespace-nowrap"
                onMouseDown={(e) => e.stopPropagation()} // Prevent dragging card when clicking toolbar
            >

                {/* Font Family */}
                <Dropdown 
                    value={<span className="font-medium text-[13px] truncate max-w-[80px]">{content.fontFamily}</span>}
                    width="w-48"
                >
                    {FONT_FAMILIES.map(font => (
                        <button
                            key={font.name}
                            onClick={() => updateField('fontFamily', font.name)}
                            className="w-full text-left px-3 py-2 text-[14px] hover:bg-gray-50 flex items-center justify-between group"
                            style={{ fontFamily: font.name }}
                        >
                            {font.label}
                            {content.fontFamily === font.name && <div className="w-1.5 h-1.5 rounded-full bg-blue-500" />}
                        </button>
                    ))}
                </Dropdown>

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Font Size */}
                <div className="flex items-center gap-0.5 bg-gray-50 rounded-lg border border-gray-100 px-1 h-8">
                     <button 
                        onClick={() => updateField('fontSize', Math.max(6, (content.fontSize || 24) - 2))}
                        className="w-6 h-full flex items-center justify-center text-gray-500 hover:text-black hover:bg-black/5 rounded"
                     >
                         <Minus size={10} />
                     </button>
                     <input 
                        type="text"
                        value={localFontSize}
                        onChange={handleFontSizeChange}
                        className="w-8 bg-transparent text-center text-[12px] font-medium focus:ring-0 border-none p-0"
                     />
                     <button 
                        onClick={() => updateField('fontSize', Math.min(200, (content.fontSize || 24) + 2))}
                        className="w-6 h-full flex items-center justify-center text-gray-500 hover:text-black hover:bg-black/5 rounded"
                     >
                         <Plus size={10} />
                     </button>
                     {/* Preset Dropdown Trigger */}
                     <Dropdown value={null} width="w-20">
                         {FONT_SIZES.map(size => (
                             <button 
                                key={size}
                                onClick={() => updateField('fontSize', size)}
                                className="w-full text-left px-3 py-1.5 text-[12px] hover:bg-gray-50"
                             >
                                 {size} px
                             </button>
                         ))}
                     </Dropdown>
                </div>

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Basic Styles */}
                <div className="flex items-center gap-0.5">
                    <button onClick={() => updateField('isBold', !content.isBold)} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.isBold ? 'bg-blue-50 text-blue-600' : 'text-gray-600'}`}>
                        <Bold size={14} />
                    </button>
                    <button onClick={() => updateField('isItalic', !content.isItalic)} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.isItalic ? 'bg-blue-50 text-blue-600' : 'text-gray-600'}`}>
                        <Italic size={14} />
                    </button>
                    <button onClick={() => updateField('isUnderline', !content.isUnderline)} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.isUnderline ? 'bg-blue-50 text-blue-600' : 'text-gray-600'}`}>
                        <Underline size={14} />
                    </button>
                </div>

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Colors */}
                <ColorPicker 
                    color={content.color} 
                    onChange={(c) => updateField('color', c)} 
                    icon={<TypeIcon size={14} className="text-gray-600" />}
                />
                <ColorPicker 
                    color={content.highlightColor || 'transparent'} 
                    onChange={(c) => updateField('highlightColor', c)} 
                    icon={<PaintBucket size={14} className="text-gray-600" />}
                />

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Alignment */}
                 <button onClick={() => updateField('textAlign', 'left')} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.textAlign === 'left' ? 'bg-gray-100 text-black' : 'text-gray-400'}`}><AlignLeft size={14} /></button>
                 <button onClick={() => updateField('textAlign', 'center')} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.textAlign === 'center' ? 'bg-gray-100 text-black' : 'text-gray-400'}`}><AlignCenter size={14} /></button>
                 <button onClick={() => updateField('textAlign', 'right')} className={`w-8 h-8 rounded-lg flex items-center justify-center hover:bg-gray-100 ${content.textAlign === 'right' ? 'bg-gray-100 text-black' : 'text-gray-400'}`}><AlignRight size={14} /></button>

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Shapes */}
                <Dropdown 
                    value={
                        <div className="flex items-center gap-1.5">
                            {SHAPES.find(s => s.id === content.shape)?.icon}
                        </div>
                    }
                    width="w-32"
                >
                    <div className="p-1 grid grid-cols-1 gap-0.5">
                        {SHAPES.map(s => (
                            <button
                                key={s.id}
                                onClick={() => updateField('shape', s.id)}
                                className={`flex items-center gap-2 px-3 py-2 text-[13px] rounded-lg hover:bg-gray-50 w-full text-left ${content.shape === s.id ? 'bg-blue-50 text-blue-600' : 'text-gray-700'}`}
                            >
                                {s.icon}
                                {s.label}
                            </button>
                        ))}
                    </div>
                </Dropdown>

            </div>
        )}

        {/* --- EDITOR CONTENT --- */}
        <div 
            className={`${shapeStyles.className} ${content.shape === 'diamond' ? 'aspect-square flex items-center justify-center' : ''}`}
            style={shapeStyles.style}
        >
            <div
            ref={editorRef}
            contentEditable
            suppressContentEditableWarning
            onBlur={handleBlur}
            onFocus={() => setIsEditing(true)}
            className={`
                outline-none min-w-[20px]
                ${isEditing ? 'cursor-text' : 'cursor-default'}
                ${content.shape === 'diamond' ? 'transform rotate-45' : ''} 
            `}
            style={{
                fontSize: `${content.fontSize}px`,
                fontFamily: content.fontFamily,
                textAlign: content.textAlign,
                color: content.color,
                fontWeight: content.isBold ? 'bold' : 'normal',
                fontStyle: content.isItalic ? 'italic' : 'normal',
                textDecoration: content.isUnderline ? 'underline' : 'none',
                lineHeight: 1.3,
                whiteSpace: 'pre-wrap',
                // If diamond, we counter rotate text roughly, though CSS clip-path is better for diamonds usually. 
                // For this implementation, we allow text to just flow or simple rotation logic if needed.
                // Keeping simple: text inside rotated square.
            }}
            onKeyDown={(e) => e.stopPropagation()} 
            >
            {content.text}
            </div>
        </div>

        {/* Placeholder if empty */}
        {!content.text && !isEditing && (
            <div 
                className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-30 italic whitespace-nowrap"
                style={{ fontSize: `${content.fontSize}px` }}
            >
                Type something...
            </div>
        )}
      </div>
    </BaseCard>
  );
};

