// --- CONSTANTS ---

const FONT_FAMILIES = [
  { name: 'Inter', label: 'Inter' },
  { name: 'Roboto', label: 'Roboto' },
  { name: 'Open Sans', label: 'Open Sans' },
  { name: 'Playfair Display', label: 'Playfair' },
  { name: 'Montserrat', label: 'Montserrat' },
  { name: 'Lato', label: 'Lato' },
  { name: 'Merriweather', label: 'Merriweather' },
  { name: 'Comic Neue', label: 'Comic' },
  { name: 'Courier Prime', label: 'Mono' },
  { name: 'Abril Fatface', label: 'Display' },
];

const FONT_SIZES = [12, 14, 16, 18, 24, 32, 48, 64, 96, 128, 160];

const PALETTE = [
  '#000000', '#545454', '#737373', '#A6A6A6', '#D9D9D9', '#FFFFFF',
  '#E03E3E', '#D9730D', '#D9B310', '#0B6E99', '#0F7B6C', '#64473A',
  '#FFB8B8', '#FAE3B3', '#FFF6CC', '#D4ECF7', '#D3F5EF', '#EADBD6'
];

const SHAPES: { id: TextShape; icon: React.ReactNode; label: string }[] = [
  { id: 'none', icon: <Type size={14} />, label: 'None' },
  { id: 'rectangle', icon: <Square size={14} />, label: 'Rect' },
  { id: 'rounded', icon: <div className="w-3.5 h-3.5 border-2 border-current rounded-md" />, label: 'Soft' },
  { id: 'pill', icon: <div className="w-4 h-3 border-2 border-current rounded-full" />, label: 'Pill' },
  { id: 'diamond', icon: <Diamond size={14} />, label: 'Diamond' },
];

// --- SUB-COMPONENTS ---

// Fix: Make children optional to resolve TS errors where children are passed via JSX nesting
const Dropdown = ({ 
  label, 
  value, 
  children, 
  width = 'w-48' 
}: { 
  label?: React.ReactNode; 
  value?: React.ReactNode; 
  children?: React.ReactNode; 
  width?: string; 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (ref.current && !ref.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className="relative" ref={ref}>
      <button 
        onClick={(e) => { e.stopPropagation(); setIsOpen(!isOpen); }}
        className="flex items-center gap-1.5 px-2 py-1.5 hover:bg-gray-100 rounded-lg transition-colors text-gray-700 h-8"
      >
        {value || label}
        <ChevronDown size={10} className="text-gray-400" />
      </button>
      {isOpen && (
        <div 
          className={`absolute top-full mt-1 left-0 ${width} max-h-64 overflow-y-auto bg-white rounded-xl shadow-xl border border-gray-100 z-[200] p-1 animate-in fade-in zoom-in-95 duration-100 no-drag`}
          onMouseDown={(e) => e.stopPropagation()}
        >
          {children}
        </div>
      )}
    </div>
  );
};

const ColorPicker = ({ 
