};

interface TextCardProps {
  card: CardData;
  isSelected: boolean;
  onSelect: (id: string) => void;
  onMove: (id: string, x: number, y: number) => void;
  onDelete: (id: string) => void;
  onUpdateContent: (id: string, content: any) => void;
  zoomScale: number;
}

export const TextCard: React.FC<TextCardProps> = (props) => {
  const { card, onUpdateContent, isSelected } = props;
  const content = card.content as TextCardContent;
  const editorRef = useRef<HTMLDivElement>(null);
  const [isEditing, setIsEditing] = useState(false);

  // Local state for font size input to allow typing
  const [localFontSize, setLocalFontSize] = useState<string>(content.fontSize?.toString() || "24");

  // Initialize defaults
  useEffect(() => {
    if (!content.fontFamily) {
        onUpdateContent(card.id, {
            ...content,
            fontSize: content.fontSize || 24,
            fontFamily: 'Inter',
            textAlign: 'left',
            color: '#1C1C1E',
            shape: 'none',
            highlightColor: 'transparent'
        });
    }
  }, []);

  useEffect(() => {
      setLocalFontSize(content.fontSize?.toString() || "24");
  }, [content.fontSize]);

  const handleBlur = () => {
    if (editorRef.current) {
        onUpdateContent(card.id, { ...content, text: editorRef.current.innerText });
    }
    setIsEditing(false);
  };

  const updateField = (key: keyof TextCardContent, value: any) => {
      onUpdateContent(card.id, { ...content, [key]: value });
  };

  const handleFontSizeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setLocalFontSize(e.target.value);
      const val = parseInt(e.target.value);
      if (!isNaN(val) && val > 0) {
          updateField('fontSize', val);
      }
  };

  // --- RENDERING HELPERS ---

  const getShapeStyles = () => {
      const base = "w-full h-full flex flex-col justify-center transition-all duration-200";
      const padding = content.shape !== 'none' ? 'px-6 py-4' : 'px-1 py-1';

      let shapeClass = '';
      switch (content.shape) {
          case 'rectangle': shapeClass = 'rounded-none'; break;
          case 'rounded': shapeClass = 'rounded-2xl'; break;
          case 'pill': shapeClass = 'rounded-full'; break;
          case 'diamond': shapeClass = ''; break; // Diamond handled via transform container if needed, or keeping simple
          case 'parallelogram': shapeClass = ''; break;
          default: shapeClass = ''; 
      }

      // Diamond logic is tricky with CSS only for variable text without cutting off. 
      // For MVP we stick to basic borders.

      return {
          className: `${base} ${shapeClass} ${padding}`,
          style: {
              backgroundColor: content.highlightColor || 'transparent',
              // Diamond simulation (simplified)
              transform: content.shape === 'diamond' ? 'rotate(0deg)' : 'none', 
          }
      };
  };

  const shapeStyles = getShapeStyles();

  return (
    <BaseCard {...props} variant="minimal">
      <div className="relative group min-w-[50px]">

        {/* --- RICH TEXT TOOLBAR --- */}
        {isSelected && (
            <div 
                className="absolute -top-16 left-1/2 -translate-x-1/2 flex items-center gap-1 p-1.5 bg-white rounded-xl shadow-[0_8px_30px_rgba(0,0,0,0.12)] border border-gray-100 z-[100] animate-in slide-in-from-bottom-2 fade-in duration-200 no-drag whitespace-nowrap"
                onMouseDown={(e) => e.stopPropagation()} // Prevent dragging card when clicking toolbar
            >

                {/* Font Family */}
                <Dropdown 
                    value={<span className="font-medium text-[13px] truncate max-w-[80px]">{content.fontFamily}</span>}
                    width="w-48"
                >
                    {FONT_FAMILIES.map(font => (
                        <button
                            key={font.name}
                            onClick={() => updateField('fontFamily', font.name)}
                            className="w-full text-left px-3 py-2 text-[14px] hover:bg-gray-50 flex items-center justify-between group"
                            style={{ fontFamily: font.name }}
                        >
                            {font.label}
                            {content.fontFamily === font.name && <div className="w-1.5 h-1.5 rounded-full bg-blue-500" />}
                        </button>
                    ))}
                </Dropdown>

                <div className="w-px h-5 bg-gray-200 mx-1"></div>

                {/* Font Size */}
                <div className="flex items-center gap-0.5 bg-gray-50 rounded-lg border border-gray-100 px-1 h-8">
                     <button 
                        onClick={() => updateField('fontSize', Math.max(6, (content.fontSize || 24) - 2))}
                        className="w-6 h-full flex items-center justify-center text-gray-500 hover:text-black hover:bg-black/5 rounded"
                     >
                         <Minus size={10} />
                     </button>
                     <input 
                        type="text"
                        value={localFontSize}
                        onChange={handleFontSizeChange}
                        className="w-8 bg-transparent text-center text-[12px] font-medium focus:ring-0 border-none p-0"
                     />
                     <button 
                        onClick={() => updateField('fontSize', Math.min(200, (content.fontSize || 24) + 2))}
                        className="w-6 h-full flex items-center justify-center text-gray-500 hover:text-black hover:bg-black/5 rounded"
                     >
                         <Plus size={10} />
                     </button>
                     {/* Preset Dropdown Trigger */}
                     <Dropdown value={null} width="w-20">
                         {FONT_SIZES.map(size => (
                             <button 
